#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
long long n,dp[100010];
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        dp[i]=y*(dp[i-1]+1)%mod*fastpow((y-x+mod)%mod,mod-2)%mod;
    }
    printf("%lld",dp[n]);
    return 0;
}
